"""Page compilation and formatting utility class for web template builders."""

import logging
import os
import re
from processing.format import format_web_file

logger = logging.getLogger(__name__)


class PageBuilder:
  """Helper class to load, modify, normalize, and compile HTML templates."""

  @classmethod
  def from_string(cls, content: str) -> 'PageBuilder':
    """Creates a PageBuilder instance directly from an in-memory string.

    Args:
        content (str): The HTML string content.

    Returns:
        PageBuilder: The builder instance.
    """
    instance = cls.__new__(cls)
    instance.template_path = None
    instance.html = content
    return instance

  def __init__(self, template_path: str):
    """Initializes the builder by reading the template file from disk.

    Args:
        template_path (str): Absolute path to the template HTML file.

    Raises:
        FileNotFoundError: If template file does not exist.
    """
    if not os.path.exists(template_path):
      raise FileNotFoundError(f"Template path {template_path} does not exist")
    self.template_path = template_path
    with open(template_path, 'r', encoding='utf-8') as f:
      self.html = f.read()

  def replace(self,
              target: str,
              replacement: str,
              count: int = -1) -> 'PageBuilder':
    """Replaces target string with replacement content.

    Args:
        target (str): Target string to locate and replace.
        replacement (str): String value to replace the target with.
        count (int, optional): Maximum occurrences to replace. Defaults to -1
          (all).

    Returns:
        PageBuilder: Self for method chaining.
    """
    self.html = self.html.replace(target, replacement, count)
    return self

  def replace_pattern(self,
                      pattern: str,
                      replacement: str,
                      flags: int = re.DOTALL) -> 'PageBuilder':
    """Replaces matching pattern using regular expression substitution.

    Args:
        pattern (str): Regular expression pattern to search for.
        replacement (str): Replacement string.
        flags (int, optional): Regex matching flags. Defaults to re.DOTALL.

    Returns:
        PageBuilder: Self for method chaining.
    """
    self.html = re.sub(pattern, replacement, self.html, flags=flags)
    return self

  def enable_lazy_loading(self) -> 'PageBuilder':
    """Injects loading="lazy" into all image elements referencing local images.

    Returns:
        PageBuilder: Self for method chaining.
    """
    self.html = self.html.replace('<img src="image/',
                                  '<img loading="lazy" src="image/')
    return self

  def normalize_headers(self) -> 'PageBuilder':
    """Sanitizes headers to replace '&amp;' with 'and' for cleaner layout.

    Returns:
        PageBuilder: Self for method chaining.
    """
    self.html = self.html.replace('<h4>Bots &amp; Automation</h4>',
                                  '<h4>Bots and Automation</h4>')
    self.html = self.html.replace('<h4>Audio &amp; Music Tech</h4>',
                                  '<h4>Audio and Music Tech</h4>')
    self.html = self.html.replace('<h4>Fermentation &amp; Hobbies</h4>',
                                  '<h4>Fermentation</h4>')
    self.html = self.html.replace('<h4>School &amp; Education</h4>',
                                  '<h4>School and Education</h4>')
    return self

