  def save(self, output_path: str, format_content: bool = True) -> None:
    """Saves the compiled HTML page, formatting whitespace if requested.

    Args:
        output_path (str): Absolute path to write the output HTML file to.
        format_content (bool, optional): Runs standard whitespace formatting.
          Defaults to True.
    """
    with open(output_path, 'w', encoding='utf-8') as f:
      f.write(self.html)

    if format_content:
      format_web_file(output_path)

    logger.info('Successfully compiled and wrote page to %s', output_path)
